// Normalize webhook input. Supported channels: Instagram + TikTok + LinkedIn.
const raw = $input.first().json;
const body = raw.body || raw;

const channels = Array.isArray(body.channels) ? body.channels : [];
const maxPosts = Math.min(Math.max(parseInt(body.maxPosts || 30, 10), 5), 100);
const brandId  = body.brand_id || body.brandId || null;
const weights  = body.scoringWeights || { engagement: 0.5, reach: 0.3, saves: 0.2 };

if (!channels.length) {
  throw new Error('No channels provided. Expected body.channels = [{ name, handle, profileUrl }, ...]');
}

const out = { brandId, maxPosts, weights, channels: [] };

for (const c of channels) {
  const name = (c.name || '').trim();
  const handle = (c.handle || '').replace(/^@/, '').trim();
  const profileUrl = (c.profileUrl || '').trim();
  if (!name) continue;

  let normalized = { name, handle, profileUrl, enabled: false };

  if (/instagram/i.test(name)) {
    if (handle) { normalized.profileUrl = `https://www.instagram.com/${handle}/`; normalized.enabled = true; }
  } else if (/tiktok/i.test(name)) {
    if (handle) { normalized.profileUrl = `https://www.tiktok.com/@${handle}`;    normalized.enabled = true; }
  } else if (/linkedin/i.test(name)) {
    if (handle || profileUrl) {
      normalized.profileUrl = (profileUrl || `https://www.linkedin.com/company/${handle}/`).replace(/\/$/, '');
      normalized.enabled = true;
    }
  } else {
    continue;
  }

  out.channels.push(normalized);
}

out.scanInstagram = out.channels.find(c => /instagram/i.test(c.name) && c.enabled) || null;
out.scanTikTok    = out.channels.find(c => /tiktok/i.test(c.name)    && c.enabled) || null;
out.scanLinkedIn  = out.channels.find(c => /linkedin/i.test(c.name)  && c.enabled) || null;

return [{ json: out }];

// Collapse Instagram Apify POSTS output into ONE { channel, meta, posts }.
const cfg = $('⚙️ Config & Route').first().json;
const metaIn = cfg.scanInstagram || { name: 'Instagram', handle: '', profileUrl: '' };
const raw = $input.all().map(it => it && it.json ? it.json : it).filter(Boolean);

function nz(v) { return typeof v === 'number' && isFinite(v) ? v : 0; }

const meta = { ...metaIn, followers: null };

const posts = raw.map((p, i) => {
  const text = p.caption || p.text || '';
  const url  = p.url || (p.shortCode ? `https://www.instagram.com/p/${p.shortCode}/` : '');
  return {
    id: p.id || p.shortCode || `ig-${i}`,
    channel: 'Instagram',
    text: String(text).slice(0, 2000),
    snippet: String(text).replace(/\s+/g, ' ').slice(0, 180),
    format: (p.type || p.productType || 'post').toString().toLowerCase(),
    publishedAt: p.timestamp || p.takenAt || null,
    url,
    metrics: {
      likes:       nz(p.likesCount),
      comments:    nz(p.commentsCount),
      shares:      0,
      impressions: nz(p.videoViewCount || p.videoPlayCount || 0),
    },
  };
});

return [{ json: { channel: 'Instagram', meta, posts } }];

// Collapse TikTok Apify POSTS output. clockworks/tiktok-scraper returns FLAT keys.
const cfg = $('⚙️ Config & Route').first().json;
const metaIn = cfg.scanTikTok || { name: 'TikTok', handle: '', profileUrl: '' };
const raw = $input.all().map(it => it && it.json ? it.json : it).filter(Boolean);

function nz(v) { return typeof v === 'number' && isFinite(v) ? v : 0; }
function g(p, ...keys) {
  for (const k of keys) { if (p[k] !== undefined && p[k] !== null) return p[k]; }
  return undefined;
}

let followers = null;
for (const p of raw) {
  const am = p.authorMeta || {};
  if (am.fans != null && Number.isFinite(am.fans)) { followers = am.fans; break; }
}
const meta = { ...metaIn, followers };

const posts = raw.map((p, i) => {
  const text = p.text || p.desc || '';
  const url  = p.webVideoUrl || p.videoUrl || '';
  const id   = p.id || (url.match(/video\/(\d+)/) || [])[1] || `tt-${i}`;
  return {
    id: String(id),
    channel: 'TikTok',
    text: String(text).slice(0, 2000),
    snippet: String(text).replace(/\s+/g, ' ').slice(0, 180),
    format: 'video',
    publishedAt: p.createTimeISO || (p.createTime ? new Date(p.createTime * 1000).toISOString() : null),
    url,
    metrics: {
      likes:       nz(g(p, 'diggCount')    || g(p['stats'] || {}, 'diggCount')),
      comments:    nz(g(p, 'commentCount') || g(p['stats'] || {}, 'commentCount')),
      shares:      nz(g(p, 'shareCount')   || g(p['stats'] || {}, 'shareCount')),
      impressions: nz(g(p, 'playCount')    || g(p['stats'] || {}, 'playCount')),
    },
  };
});

return [{ json: { channel: 'TikTok', meta, posts } }];

// Receives items from Merge LinkedIn (1 company item + N post items in one batch).
// Separates them by shape: company items have followerCount/employeeCount; post items have content/engagement/postedAt.
const cfg = $('⚙️ Config & Route').first().json;
const metaIn = cfg.scanLinkedIn || { name: 'LinkedIn', handle: '', profileUrl: '' };
const raw = $input.all().map(it => it && it.json ? it.json : it).filter(Boolean);

function nz(v) { return typeof v === 'number' && isFinite(v) ? v : 0; }
function isCompanyItem(x) { return x && (x.followerCount != null || x.employeeCount != null || (x.universalName != null && x.linkedinUrl && !x.content && !x.engagement)); }
function isPostItem(x)    { return x && (x.content != null || x.engagement != null || x.postedAt != null); }

let followers = null;
const companyItems = raw.filter(isCompanyItem);
for (const c of companyItems) {
  const f = c.followerCount ?? c.followers ?? c.followers_count;
  if (f != null && Number.isFinite(Number(f))) { followers = Number(f); break; }
}
const meta = { ...metaIn, followers };

const postItems = raw.filter(isPostItem);
const posts = postItems.map((p, i) => {
  const text = p.content || p.text || '';
  const url  = p.linkedinUrl || p.url || '';
  const id   = String(p.id || (url.match(/(?:activity|posts)[/-](\d+)/) || [])[1] || `li-${i}`);
  const eng  = p.engagement || {};
  const ts   = p.postedAt && (p.postedAt.date || (p.postedAt.timestamp && new Date(p.postedAt.timestamp).toISOString())) || p.publishedAt || null;
  let format = (p.type || 'post').toString().toLowerCase();
  if (Array.isArray(p.images) && p.images.length > 1) format = 'carousel';
  else if (p.video || p.videoUrl) format = 'video';
  else if (p.article) format = 'article';
  else if (Array.isArray(p.images) && p.images.length === 1) format = 'image';
  return {
    id,
    channel: 'LinkedIn',
    text: String(text).slice(0, 2000),
    snippet: String(text).replace(/\s+/g, ' ').slice(0, 180),
    format,
    publishedAt: ts,
    url,
    metrics: {
      likes:       nz(eng.likes ?? eng.reactions_total),
      comments:    nz(eng.comments),
      shares:      nz(eng.shares ?? eng.reposts),
      impressions: 0,
    },
  };
});

console.log(`[Bundle LinkedIn] raw=${raw.length} company=${companyItems.length} posts=${postItems.length} → followers=${followers}, posts=${posts.length}`);
return [{ json: { channel: 'LinkedIn', meta, posts } }];

// Receives 1 item per channel, scores posts, builds top/bottom + 7×24 heatmap.
const items = $input.all().map(it => it.json);
const cfg = $('⚙️ Config & Route').first().json;
const weights = cfg.weights || { engagement: 0.5, reach: 0.3, saves: 0.2 };

const expected = [];
if (cfg.scanInstagram) expected.push({ name: 'Instagram', meta: cfg.scanInstagram });
if (cfg.scanTikTok)    expected.push({ name: 'TikTok',    meta: cfg.scanTikTok });
if (cfg.scanLinkedIn)  expected.push({ name: 'LinkedIn',  meta: cfg.scanLinkedIn });

const bundleByChannel = {};
for (const it of items) { if (it && it.channel) bundleByChannel[it.channel] = it; }
const merged = expected.map(ec => bundleByChannel[ec.name] || { channel: ec.name, meta: ec.meta, posts: [] });

function engagementRate(m) {
  const interactions = (m.likes || 0) + (m.comments || 0) + (m.shares || 0);
  const denom = (m.impressions || 0) > 0 ? m.impressions : 1000;
  return +((interactions / denom) * 100).toFixed(2);
}

function buildHeatmap(posts) {
  const m = Array.from({ length: 7 }, () => Array.from({ length: 24 }, () => ({ count: 0, totalEr: 0 })));
  for (const p of posts) {
    if (!p.publishedAt) continue;
    const d = new Date(p.publishedAt);
    if (isNaN(d.getTime())) continue;
    const dow = d.getUTCDay(), hr = d.getUTCHours();
    const cell = m[dow][hr];
    m[dow][hr] = { count: cell.count + 1, totalEr: cell.totalEr + (p.engagementRate || 0) };
  }
  return m.map(row => row.map(c => ({ count: c.count, avgEr: c.count ? +(c.totalEr / c.count).toFixed(2) : 0 })));
}

const CHANNEL_COLOR = { Instagram: '#E4405F', TikTok: '#010101', LinkedIn: '#0A66C2' };
const CHANNEL_ICON  = { Instagram: 'instagram', TikTok: 'music', LinkedIn: 'linkedin' };

const out = { cfg, channels: [] };

for (const item of merged) {
  const name = item.channel;
  const meta = item.meta || {};
  const rawPosts = Array.isArray(item.posts) ? item.posts : [];

  const posts = rawPosts.map(p => ({ ...p, engagementRate: engagementRate(p.metrics || {}) }));
  const maxReach = Math.max(1, ...posts.map(p => p.metrics?.impressions || 0));
  const maxSaves = Math.max(1, ...posts.map(p => p.metrics?.shares || 0));
  const maxEr    = Math.max(0.01, ...posts.map(p => p.engagementRate));

  const scored = posts.map(p => {
    const eN = (p.engagementRate || 0) / maxEr;
    const rN = (p.metrics?.impressions || 0) / maxReach;
    const sN = (p.metrics?.shares || 0) / maxSaves;
    const score = (weights.engagement || 0.5) * eN + (weights.reach || 0.3) * rN + (weights.saves || 0.2) * sN;
    return { ...p, score: +score.toFixed(3) };
  });

  const sorted = [...scored].sort((a, b) => b.score - a.score);
  const topPosts    = sorted.slice(0, 5);
  const bottomPosts = posts.length > 5 ? sorted.slice(-3).reverse() : [];

  const avgEr = posts.length ? +(posts.reduce((s, p) => s + p.engagementRate, 0) / posts.length).toFixed(2) : 0;
  const cadence = posts.length ? +((posts.length / 12).toFixed(2)) : 0;

  out.channels.push({
    name,
    icon: CHANNEL_ICON[name] || name.toLowerCase(),
    color: CHANNEL_COLOR[name] || '#666',
    handle: '@' + (meta.handle || ''),
    profileUrl: meta.profileUrl || '',
    enabled: true,
    followers: (meta.followers != null && Number.isFinite(Number(meta.followers))) ? Number(meta.followers) : null,
    postingCadence: cadence,
    avgEngagementRate: avgEr,
    primaryFormat: (posts[0] && posts[0].format) || 'post',
    posts: scored,
    topPosts,
    bottomPosts,
    cadenceHeatmap: buildHeatmap(scored),
  });
}

console.log('[WF02 Compute] channels:', out.channels.map(c => `${c.name}(posts=${c.posts.length}, followers=${c.followers})`).join(', '));
return [{ json: out }];

