// Merge tone analysis (Claude) back into the channel objects (metrics).
const prev = $('Compute Metrics & Heatmap').first().json;
const rawText = $input.first().json?.content?.[0]?.text || '';

let tone = { channels: [] };
try {
  const cleaned = rawText.replace(/^```json?\s*/i, '').replace(/\s*```$/i, '').trim();
  tone = JSON.parse(cleaned);
} catch (e) {
  const m = rawText.match(/\{[\s\S]*\}/);
  if (m) { try { tone = JSON.parse(m[0]); } catch {} }
}

const toneByName = {};
for (const t of (tone.channels || [])) {
  toneByName[(t.name || '').toLowerCase()] = t;
}

const channels = (prev.channels || []).map(c => {
  const t = toneByName[c.name.toLowerCase()] || {};
  const byId = new Map((t.whyItWorked || []).map(w => [String(w.postId), w.reason]));
  const topPosts = (c.topPosts || []).map(p => ({ ...p, whyItWorked: byId.get(String(p.id)) || '' }));
  return {
    name: c.name,
    icon: c.icon,
    color: c.color,
    handle: c.handle,
    profileUrl: c.profileUrl,
    enabled: true,
    followers: c.followers,
    postingCadence: c.postingCadence,
    avgEngagementRate: c.avgEngagementRate,
    primaryFormat: c.primaryFormat,
    tone: t.tone || { formal_vs_casual: 50, technical_vs_accessible: 50, serious_vs_playful: 50, humble_vs_bold: 50, short_vs_expansive: 50 },
    toneSummary: t.toneSummary || '',
    voiceRules: t.voiceRules || { always: [], never: [] },
    topPosts,
    bottomPosts: c.bottomPosts || [],
    cadenceHeatmap: c.cadenceHeatmap,
  };
});

const result = {
  brand_id: prev.cfg && prev.cfg.brandId,
  scanned_at: new Date().toISOString(),
  scoringWeights: prev.cfg && prev.cfg.weights,
  channels,
};

console.log('[WF02 Final] channels:', channels.map(c => `${c.name}(top=${c.topPosts.length})`).join(', '));
return [{ json: result }];
